This test has a compiler error accessing the ViewModel. What's wrong and how do you fix it?

```swift
class ItemViewModelTests: XCTestCase {
    var sut: ItemViewModel!

    func testInitialStateIsLoading() {
        sut = ItemViewModel(repository: MockItemRepository())
        XCTAssertEqual(sut.state, .loading)  // Error: expression is async
    }
}
