evals.expected_output:
```swift
@MainActor
class SearchViewModelTests: XCTestCase {
    var sut: SearchViewModel!
    var mockRepo: MockSearchRepository!

    override func setUp() async throws {
        mockRepo = MockSearchRepository()
        sut = SearchViewModel(repository: mockRepo)
        addTeardownBlock { [weak sut] in XCTAssertNil(sut) }  // leak detection
    }

    override func tearDown() async throws {
        sut = nil
        mockRepo = nil
    }

    func testCancellationDoesNotChangeState() async throws {
        mockRepo.shouldThrowCancellation = true
        let stateBefore = sut.state
        await sut.search(query: "test")
        // State should be .loading (set before cancellation) not .error
        // Verify it did NOT set .error
        if case .error = sut.state { XCTFail("CancellationError must not set .error state") }
        XCTAssertEqual(mockRepo.searchCallCount, 1)
    }
}

class MockSearchRepository: SearchRepositoryProtocol {
    var searchCallCount = 0
    var stubbedResults: [Result] = []
    var shouldThrowCancellation = false

    func search(query: String) async throws -> [Result] {
        searchCallCount += 1
        if shouldThrowCancellation { throw CancellationError() }
        return stubbedResults
    }
}
```

